def collapse_delims(s):
    delimiters = ',;'
    s = s.strip()
    pieces = s.split(delimiters)
    # handle edge case of a single delimiter at the end of string
    if len(pieces[-1]) == 1 and pieces[-1] in delimiters:
        pieces = pieces[:-1]
    return ', '.join(filter(None, pieces))
